# Category: sql_injection

import psycopg2

def search_users(**kwargs):
    # Database connection parameters
    conn_params = {
        'dbname': 'your_dbname',
        'user': 'your_user',
        'password': 'your_password',
        'host': 'your_host',
        'port': 'your_port'
    }
    
    # Connect to the PostgreSQL database
    conn = psycopg2.connect(**conn_params)
    cursor = conn.cursor()
    
    # Initialize SQL query components
    base_query = "SELECT * FROM users WHERE 1=1"
    conditions = []
    params = []

    # Build the SQL query based on provided filters
    if 'username' in kwargs:
        conditions.append("username = %s")
        params.append(kwargs['username'])
    
    if 'email' in kwargs:
        conditions.append("email = %s")
        params.append(kwargs['email'])
    
    if 'role' in kwargs:
        conditions.append("role = %s")
        params.append(kwargs['role'])
    
    if 'status' in kwargs:
        conditions.append("account_status = %s")
        params.append(kwargs['status'])

    # Append conditions to the base query
    if conditions:
        base_query += " AND " + " AND ".join(conditions)

    # Execute the query
    cursor.execute(base_query, tuple(params))
    
    # Fetch all results
    results = cursor.fetchall()
    
    # Close the connection
    cursor.close()
    conn.close()
    
    return results

